```class Solution {
public:
    int maximumLength(string s) {
        int n = s.size();
        int res = -1;
        for (int i = 1; i <= n; i++) {
            unordered_map<char, int> mp;
            for (int j = 0; j < i; j++) {
                mp[s[j]]++;
            }
            int count = 0;
            for (auto it = mp.begin(); it != mp.end(); it++) {
                if (it->second > 0) {
                    count++;
                }
            }
            if (count == 1) {
                res = max(res, i);
            }
        }
        return res;
    }
};```
